// === GENERADOR DE CUADRANTES C21 — CASAS + TERRENOS ===
// Grid geográfico Equipetrol × 2 tipos de propiedad
// PRD: docs/backlog/CASAS_TERRENOS_PRD.md

const LAT_SUR = -17.775;
const LAT_NORTE = -17.750;
const LON_OESTE = -63.205;
const LON_ESTE = -63.185;
const STEP = 0.010;

const cookieId = 'sici_ct_' + Math.random().toString(36).substring(2, 15);
const cookie = `PHPSESSID=${cookieId}`;

// C21: tipo_casa-o-terreno combinado da 404. Requests separadas.
const TIPOS = ['casa', 'terreno'];

const cuadrantes = [];
let gridId = 1;

for (const tipo of TIPOS) {
  for (let lat = LAT_SUR; lat < LAT_NORTE; lat += STEP) {
    for (let lon = LON_OESTE; lon < LON_ESTE; lon += STEP) {
      const south = lat;
      const west = lon;
      const north = lat + STEP;
      const east = lon + STEP;

      const coordString = `coordenadas_${north.toFixed(6)},${east.toFixed(6)},${south.toFixed(6)},${west.toFixed(6)}`;

      cuadrantes.push({
        json: {
          grid_id: gridId++,
          tipo_url: tipo,
          path_coordenadas: coordString,
          cookie: cookie,
          fuente: 'century21'
        }
      });
    }
  }
}

console.log(`Generados ${cuadrantes.length} cuadrantes (${TIPOS.length} tipos × grid)`);
return cuadrantes;

// === EXTRAER PROPIEDADES DEL RESPONSE — CASAS/TERRENOS ===
// Parsing idéntico a deptos (misma estructura JSON C21)
const response = $input.first().json;

let propiedades = [];
if (Array.isArray(response)) {
  propiedades = response;
} else if (response.results) {
  propiedades = response.results;
} else if (response.datas && response.datas.results) {
  propiedades = response.datas.results;
}

if (!propiedades || propiedades.length === 0) {
  return [];
}

return propiedades.map(prop => {
  const moneda = prop.moneda || 'USD';
  const precioOriginal = prop.precio || null;

  let precioUsd = null;
  if (precioOriginal !== null && moneda === 'USD') {
    precioUsd = precioOriginal;
  }

  return {
    json: {
      url: `https://c21.com.bo${prop.urlCorrectaPropiedad || '/propiedad/' + prop.id}`,
      fuente: 'century21',
      codigo_propiedad: String(prop.id),
      latitud: parseFloat(prop.lat) || null,
      longitud: parseFloat(prop.lon) || null,
      tipo_operacion: prop.tipoOperacion || null,
      precio_usd: precioUsd,
      precio_amount: precioOriginal,
      moneda_original: moneda,
      area_total_m2: prop.m2C != null && prop.m2C > 0 ? Number(prop.m2C) : null,
      area_terreno_m2: prop.m2T != null && prop.m2T > 0 ? Number(prop.m2T) : null,
      dormitorios: prop.recamaras || null,
      banos: prop.banos || null,
      estacionamientos: prop.estacionamientos || null,
      tipo_propiedad_original: prop.tipoPropiedad || null,
      fecha_publicacion: prop.fechaAlta || null,
      datos_json_discovery: prop,
      metodo_discovery: 'map_grid'
    }
  };
});

// === PREPARAR COMPARACIÓN ===

const snapshot = $('Aggregate Snapshot').first().json.propiedades || [];
const propiedadesBD = $('Obtener URLs Activas BD').all().map(item => item.json);

const snapshotDedup = new Map();
for (const prop of snapshot) {
  snapshotDedup.set(prop.url, prop);
}

const urlsSnapshot = new Set(snapshotDedup.keys());
const urlsBD = new Map(propiedadesBD.map(p => [p.url, { id: p.id, status: p.status }]));

const nuevas = [];
const existentes = [];
const ausentes = [];

for (const [url, prop] of snapshotDedup) {
  if (!urlsBD.has(url)) {
    nuevas.push(prop);
  } else {
    existentes.push({
      ...prop,
      _id_bd: urlsBD.get(url).id,
      _status_bd: urlsBD.get(url).status
    });
  }
}

for (const [url, info] of urlsBD) {
  if (!urlsSnapshot.has(url)) {
    if (!['inactivo_pending', 'inactivo_confirmed'].includes(info.status)) {
      ausentes.push({
        id: info.id,
        url: url,
        status_actual: info.status
      });
    }
  }
}

return [{
  json: {
    nuevas: nuevas,
    existentes: existentes,
    ausentes: ausentes,
    stats: {
      total_snapshot: snapshotDedup.size,
      total_bd: urlsBD.size,
      nuevas: nuevas.length,
      existentes: existentes.length,
      ausentes: ausentes.length
    }
  }
}];

// === LOG STATS ===
const stats = $input.first().json.stats;

console.log(`
=== COMPARACIÓN DISCOVERY C21 CASAS/TERRENOS ===
Snapshot (deduplicado): ${stats.total_snapshot}
BD activas: ${stats.total_bd}
---
Nuevas: ${stats.nuevas}
Existentes: ${stats.existentes}
Ausentes: ${stats.ausentes}
=================================================
`);

return $input.all();

// === UNIFICAR PROPIEDADES PARA DISCOVERY ===
const data = $input.first().json;
const nuevas = data.nuevas || [];
const existentes = data.existentes || [];
const todas = [...nuevas, ...existentes].filter(p => p.url);

if (todas.length === 0) {
  return [{ json: { skip: true, message: 'No hay propiedades para procesar' } }];
}

function quitarAcentos(texto) {
  if (!texto) return null;
  return texto
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function safeNum(v) { return v != null && v !== '' ? Number(v) : null; }

return todas.map(prop => ({
  json: {
    p_url: prop.url,
    p_fuente: prop.fuente || 'century21',
    p_codigo_propiedad: prop.codigo_propiedad || null,
    p_tipo_operacion: quitarAcentos(prop.tipo_operacion),
    p_tipo_propiedad_original: prop.tipo_propiedad_original || null,
    p_precio_usd: safeNum(prop.precio_usd),
    p_precio_usd_original: safeNum(prop.precio_amount),
    p_moneda_original: prop.moneda_original || null,
    p_area_total_m2: safeNum(prop.area_total_m2),
    p_dormitorios: safeNum(prop.dormitorios),
    p_banos: safeNum(prop.banos),
    p_estacionamientos: safeNum(prop.estacionamientos),
    p_latitud: safeNum(prop.latitud),
    p_longitud: safeNum(prop.longitud),
    p_fecha_publicacion: prop.fecha_publicacion || null,
    p_metodo_discovery: prop.metodo_discovery || 'map_grid',
    p_datos_json_discovery: prop.datos_json_discovery ? JSON.stringify(prop.datos_json_discovery) : '{}',
    p_area_terreno_m2: safeNum(prop.area_terreno_m2)
  }
}));

// === PROCESAR AUSENTES ===

const ausentes = $input.first().json.ausentes;

if (ausentes.length === 0) {
  return [{ json: { skip: true, message: 'No hay propiedades ausentes' } }];
}

return ausentes.map(prop => ({
  json: {
    id: prop.id,
    url: prop.url,
    status_actual: prop.status_actual
  }
}));

// === RESUMEN FINAL ===
const stats = $('Log Stats').first().json.stats;

const resumen = {
  timestamp: new Date().toISOString(),
  fuente: 'century21',
  tipo: 'casas_terrenos',
  workflow: 'Discovery Casas/Terrenos C21',
  version: '1.0.0',
  resultados: {
    snapshot_total: stats.total_snapshot,
    bd_activas: stats.total_bd,
    nuevas_insertadas: stats.nuevas,
    existentes_actualizadas: stats.existentes,
    ausentes_marcadas: stats.ausentes
  },
  status: 'completado'
};

console.log('=== DISCOVERY C21 CASAS/TERRENOS COMPLETADO ===');
console.log(JSON.stringify(resumen, null, 2));

return [{ json: resumen }];
